  ('dietitian-moex-04998', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關開放性結核病（tuberculosis）病人的敘述，下列何者錯誤？', '["有缺鐵性貧血時，適量補充鐵劑對病人仍是需要的", "蛋白質建議量為0.8～1.0g/kgIBW", "身體呈現異化代謝（catabolism）且體重下降", "營養不良會降低抗結核菌藥物的治療效果"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:38+00:00", "source_pdf_sha1": "12def22d8e48", "answer_pdf_sha1": "fb471fe128ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04999', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '大腸直腸癌病人手術後常見的營養相關症狀，下列何者正確？', '["乳糖不耐症（lactoseintolerance）", "胃輕癱（gastroparesis）", "傾食症候群（dumpingsyndrome）", "脹氣和腹痛（bloatingandcramping）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:38+00:00", "source_pdf_sha1": "12def22d8e48", "answer_pdf_sha1": "fb471fe128ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-05000', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '經常攝取下列那一套食物組合，最易增加罹癌風險？', '["燒烤牛肉串、可樂", "松阪豬肉飯糰、美式咖啡", "蒜香糯米腸、胡蘿蔔汁", "乾煎雞腿排、紅酒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:38+00:00", "source_pdf_sha1": "12def22d8e48", "answer_pdf_sha1": "fb471fe128ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
